//! Runtime helper functions for native Rust code generated by `generation.rs`.
//!
//! The bytecode interpreter implements these operations as opcodes that read
//! parameters from the bytecode stream and manipulate the stack.  Generated
//! native code calls these wrapper functions directly with explicit arguments.
//!
//! **Interpreter safety:** This module is purely additive — it does not modify
//! any interpreter code path.  It only re-exposes `Stores` methods with the
//! signatures that generated code expects.

#![allow(non_snake_case)]
#![allow(clippy::cast_possible_truncation)]
#![allow(clippy::cast_sign_loss)]
#![allow(clippy::doc_markdown)]

use crate::database::{ShowDb, Stores};
use crate::keys::DbRef;
use crate::ops;
use crate::vector;

/// Allocate a database root record for the given type.
/// The generated code calls this as `OpDatabase(stores, var, tp)` where `var` is
/// passed by value (DbRef).  The function allocates into the store referenced by
/// `db`, then returns the updated DbRef.
/// Bytecode equivalent: `OpDatabase` in `src/state/io.rs:319`.
pub fn OpDatabase(stores: &mut Stores, mut db: DbRef, db_tp: i32) -> DbRef {
    let db_tp = db_tp as u16;
    let size = stores.size(db_tp);
    stores.clear(&db);
    let r = stores.claim(&db, u32::from(size));
    stores.store_mut(&r).set_int(r.rec, 4, i32::from(db_tp));
    stores.set_default_value(db_tp, &r);
    db.store_nr = r.store_nr;
    db.rec = 1;
    db.pos = 8;
    db
}

/// Create a new record element inside a vector/sorted/index collection.
/// Returns a `DbRef` pointing to the new element with default field values.
/// Bytecode equivalent: `OpNewRecord` in `src/state/io.rs:336`.
pub fn OpNewRecord(stores: &mut Stores, data: DbRef, parent_tp: i32, fld: i32) -> DbRef {
    let parent_tp = parent_tp as u16;
    let fld = fld as u16;
    let new_value = stores.record_new(&data, parent_tp, fld);
    stores.set_default_value(
        if fld == u16::MAX {
            stores.content(parent_tp)
        } else {
            stores.content(stores.field_type(parent_tp, fld))
        },
        &new_value,
    );
    new_value
}

/// Finalize a record after its fields have been assigned.
/// For sorted/index collections this inserts the record at the correct position.
/// Bytecode equivalent: `OpFinishRecord` in `src/state/io.rs:772`.
pub fn OpFinishRecord(stores: &mut Stores, data: DbRef, record: DbRef, parent_tp: i32, fld: i32) {
    stores.record_finish(&data, &record, parent_tp as u16, fld as u16);
}

/// Free a database reference.  Closes any associated file handle first.
/// Bytecode equivalent: `OpFreeRef` in `src/state/io.rs:262`.
pub fn OpFreeRef(stores: &mut Stores, db: DbRef) {
    if db.rec != 0
        && let Some(&file_type) = stores.names.get("File")
    {
        let stored_type = stores.store(&db).get_int(db.rec, 4) as u16;
        if stored_type == file_type {
            let file_ref = stores.store(&db).get_int(db.rec, db.pos + 28);
            if file_ref != i32::MIN && (file_ref as usize) < stores.files.len() {
                stores.files[file_ref as usize] = None;
            }
        }
    }
    stores.free(&db);
}

/// Format a database record as text and append it to the output string.
/// Bytecode equivalent: `OpFormatDatabase` in `src/state/io.rs:278`.
pub fn OpFormatDatabase(
    stores: &mut Stores,
    output: &mut String,
    record: DbRef,
    db_tp: i32,
    db_format: i32,
) {
    let mut s = String::new();
    ShowDb {
        stores,
        store: record.store_nr,
        rec: record.rec,
        pos: record.pos,
        known_type: db_tp as u16,
        pretty: db_format & 1 > 0,
        json: db_format & 2 > 0,
    }
    .write(&mut s, 0);
    output.push_str(&s);
}

/// Look up a record in a collection by key values.
/// Bytecode equivalent: `OpGetRecord` in `src/state/io.rs:353`.
pub fn OpGetRecord(
    stores: &mut Stores,
    data: DbRef,
    db_tp: i32,
    key: &[crate::keys::Content],
) -> DbRef {
    if data.rec == 0 {
        DbRef {
            store_nr: data.store_nr,
            rec: 0,
            pos: 0,
        }
    } else {
        stores.find(&data, db_tp as u16, key)
    }
}

/// Extract a substring from a text value.
/// Bytecode equivalent: `OpGetTextSub` in `src/fill.rs`.
#[must_use]
pub fn OpGetTextSub(text: &str, from: i32, till: i32) -> &str {
    #![allow(clippy::cast_possible_wrap)]
    let len = text.len() as i32;
    let f = from.max(0).min(len) as usize;
    let t = till.max(0).min(len) as usize;
    if f >= t { "" } else { &text[f..t] }
}

/// Return the byte size of a database record's type.
/// Bytecode equivalent: `OpSizeofRef` in `src/state/io.rs:290`.
#[must_use]
pub fn OpSizeofRef(stores: &Stores, db: DbRef) -> i32 {
    if db.rec == 0 {
        0
    } else {
        let tp = stores.store(&db).get_int(db.rec, 4) as u16;
        i32::from(stores.size(tp))
    }
}

/// Parse a text representation into a database record.
/// Bytecode equivalent: `State::db_from_text` in `src/state/io.rs:780`.
#[must_use]
pub fn db_from_text(stores: &mut Stores, val: &str, db_tp: i32) -> DbRef {
    let db_tp = db_tp as u16;
    let db = stores.database(8);
    let into = DbRef {
        store_nr: db.store_nr,
        rec: db.rec,
        pos: 8,
    };
    stores.set_default_value(db_tp, &into);
    let mut pos = 0;
    if stores.parsing(val, &mut pos, db_tp, db_tp, u16::MAX, &into) {
        into
    } else {
        DbRef {
            store_nr: db.store_nr,
            rec: 0,
            pos: 0,
        }
    }
}

/// Deep-copy a database record: copies the raw bytes and duplicates
/// all owned sub-structures (text fields, vectors, etc.).
/// Bytecode equivalent: `State::copy_record` in `src/state/io.rs:697`.
pub fn OpCopyRecord(stores: &mut Stores, data: DbRef, to: DbRef, tp: i32) {
    let tp = tp as u16;
    let size = u32::from(stores.size(tp));
    stores.copy_block(&data, &to, size);
    stores.copy_claims(&data, &to, tp);
}

/// Sort a vector in-place using the element type's natural ordering.
/// Bytecode equivalent: `sort_vector` in `src/fill.rs:1835`.
pub fn OpSortVector(stores: &mut Stores, data: DbRef, db_tp: i32) {
    let db_tp = db_tp as u16;
    let elem_size = stores.size(db_tp);
    let is_float = db_tp == 2 || db_tp == 3;
    vector::sort_vector(&data, elem_size, is_float, &mut stores.allocations);
}

/// Insert a new default-valued element at `index` in a vector, shifting later elements right.
/// Returns a `DbRef` pointing to the newly inserted element.
/// Bytecode equivalent: `State::insert_vector` in `src/state/io.rs:819`.
pub fn OpInsertVector(
    stores: &mut Stores,
    data: DbRef,
    size: i32,
    index: i32,
    db_tp: i32,
) -> DbRef {
    let new_value = vector::insert_vector(&data, size as u32, index, &mut stores.allocations);
    stores.set_default_value(db_tp as u16, &new_value);
    new_value
}

/// Return the UTF-8 byte length of a character (encoded as `i32` in loft).
/// Returns 0 for the null character sentinel.
/// Bytecode equivalent: `State::length_character` in `src/state/text.rs:54`.
#[must_use]
pub fn OpLengthCharacter(_stores: &mut Stores, c: i32) -> i32 {
    let ch = ops::to_char(c);
    if ch == '\0' {
        0
    } else {
        i32::try_from(ch.len_utf8()).unwrap_or(0)
    }
}
